    /** Scrapes a simple HTML page and extracts title, description, and links */
    public function test_scrape_basic_html_page(): void
    {
        $engine_config = CrawlConfig::from_json(json_encode(["maxDepth" => 0, "respectRobotsTxt" => false]));
        $engine = Kreuzcrawl::createEngine($engine_config);
        $url = getenv('MOCK_SERVER_URL') . '/fixtures/scrape_basic_html_page';
        $result = Kreuzcrawl::scrape($engine, $url);
        $this->assertEquals(200, $result->statusCode);
        $this->assertEquals("text/html", trim($result->contentType));
        $this->assertNotEmpty($result->html);
        $this->assertEquals("Example Domain", trim($result->metadata->title));
        $this->assertStringContainsString("illustrative examples", $result->metadata->description);
        $this->assertNotEmpty($result->metadata->canonicalUrl);
        $this->assertGreaterThan(0, count($result->links));
        $this->assertStringContainsString("external", $result->links[0]->linkType);
        $this->assertEquals(0, count($result->images));
        $this->assertEmpty($result->metadata->ogTitle);

    }


